/**
 * Users API Resource
 * Handles all user-related API operations
 */

import { BaseResource } from './base';
import type { 
  User, 
  UserCreate, 
  UserUpdate, 
  UserListResponse,
  PaginationParams,
} from '../types';

/**
 * Users resource class
 * Provides CRUD operations for user management
 */
export class Users extends BaseResource {
  constructor(client: ReturnType<typeof import('../client').createClient>) {
    super(client as any, '/users');
  }

  /**
   * List all users with optional pagination
   * @param params - Pagination and sorting options
   * @returns List of users with metadata
   */
  async list(params?: PaginationParams): Promise<UserListResponse> {
    const query = this.buildPaginationParams(params);
    return this.get<UserListResponse>('', { params: query });
  }

  /**
   * Get a single user by ID
   * @param userId - The user ID
   * @returns User object
   * @throws {NotFoundError} If user doesn't exist
   */
  async get(userId: string): Promise<User> {
    return this.get<User>(userId);
  }

  /**
   * Create a new user
   * @param data - User creation data
   * @returns Created user
   * @throws {ValidationError} If data is invalid
   * @throws {ConflictError} If user already exists
   */
  async create(data: UserCreate): Promise<User> {
    return this.post<User>('', data as Record<string, unknown>);
  }

  /**
   * Update an existing user (full update)
   * @param userId - The user ID to update
   * @param data - User update data
   * @returns Updated user
   * @throws {NotFoundError} If user doesn't exist
   * @throws {ValidationError} If data is invalid
   */
  async update(userId: string, data: UserUpdate): Promise<User> {
    return this.put<User>(userId, data as Record<string, unknown>);
  }

  /**
   * Partially update a user
   * @param userId - The user ID to update
   * @param data - Partial user update data
   * @returns Updated user
   * @throws {NotFoundError} If user doesn't exist
   * @throws {ValidationError} If data is invalid
   */
  async patch(userId: string, data: Partial<UserUpdate>): Promise<User> {
    return this.patch<User>(userId, data as Record<string, unknown>);
  }

  /**
   * Delete a user
   * @param userId - The user ID to delete
   * @throws {NotFoundError} If user doesn't exist
   */
  async delete(userId: string): Promise<void> {
    await this.delete<void>(userId);
  }

  /**
   * Get current authenticated user
   * @returns Current user profile
   */
  async me(): Promise<User> {
    return this.get<User>('me');
  }

  /**
   * Search users by name or email
   * @param query - Search query string
   * @param params - Pagination options
   * @returns Filtered list of users
   */
  async search(query: string, params?: PaginationParams): Promise<UserListResponse> {
    const queryParams = this.buildPaginationParams(params);
    return this.get<UserListResponse>('search', { 
      params: { ...queryParams, q: query }
    });
  }

  /**
   * Activate a user account
   * @param userId - The user ID to activate
   * @returns Updated user
   */
  async activate(userId: string): Promise<User> {
    return this.post<User>(`${userId}/activate`, {});
  }

  /**
   * Deactivate a user account
   * @param userId - The user ID to deactivate
   * @returns Updated user
   */
  async deactivate(userId: string): Promise<User> {
    return this.post<User>(`${userId}/deactivate`, {});
  }

  /**
   * Resend verification email
   * @param userId - The user ID
   */
  async resendVerification(userId: string): Promise<void> {
    await this.post<void>(`${userId}/resend-verification`, {});
  }
}

/**
 * Items API Resource
 * Handles all item-related API operations
 */

import { BaseResource } from './base';
import type { 
  Item, 
  ItemCreate, 
  ItemUpdate, 
  ItemListResponse,
  PaginationParams,
  ItemStatus,
} from '../types';

/**
 * Items resource class
 * Provides CRUD operations for item management
 */
export class Items extends BaseResource {
  constructor(client: ReturnType<typeof import('../client').createClient>) {
    super(client as any, '/items');
  }

  /**
   * List all items with optional filtering and pagination
   * @param params - Pagination and optional filters
   * @returns List of items with metadata
   */
  async list(params?: PaginationParams & { status?: ItemStatus; owner_id?: string }): Promise<ItemListResponse> {
    const query: Record<string, string> = this.buildPaginationParams(params);

    if (params?.status) {
      query.status = params.status;
    }
    if (params?.owner_id) {
      query.owner_id = params.owner_id;
    }

    return this.get<ItemListResponse>('', { params: query });
  }

  /**
   * Get a single item by ID
   * @param itemId - The item ID
   * @returns Item object
   * @throws {NotFoundError} If item doesn't exist
   */
  async get(itemId: string): Promise<Item> {
    return this.get<Item>(itemId);
  }

  /**
   * Create a new item
   * @param data - Item creation data
   * @returns Created item
   * @throws {ValidationError} If data is invalid
   */
  async create(data: ItemCreate): Promise<Item> {
    return this.post<Item>('', data as Record<string, unknown>);
  }

  /**
   * Update an existing item (full update)
   * @param itemId - The item ID to update
   * @param data - Item update data
   * @returns Updated item
   * @throws {NotFoundError} If item doesn't exist
   * @throws {ValidationError} If data is invalid
   */
  async update(itemId: string, data: ItemUpdate): Promise<Item> {
    return this.put<Item>(itemId, data as Record<string, unknown>);
  }

  /**
   * Partially update an item
   * @param itemId - The item ID to update
   * @param data - Partial item update data
   * @returns Updated item
   * @throws {NotFoundError} If item doesn't exist
   * @throws {ValidationError} If data is invalid
   */
  async patch(itemId: string, data: Partial<ItemUpdate>): Promise<Item> {
    return this.patch<Item>(itemId, data as Record<string, unknown>);
  }

  /**
   * Delete an item
   * @param itemId - The item ID to delete
   * @throws {NotFoundError} If item doesn't exist
   */
  async delete(itemId: string): Promise<void> {
    await this.delete<void>(itemId);
  }

  /**
   * Archive an item
   * @param itemId - The item ID to archive
   * @returns Updated item with archived status
   */
  async archive(itemId: string): Promise<Item> {
    return this.post<Item>(`${itemId}/archive`, {});
  }

  /**
   * Unarchive an item
   * @param itemId - The item ID to unarchive
   * @returns Updated item with active status
   */
  async unarchive(itemId: string): Promise<Item> {
    return this.post<Item>(`${itemId}/unarchive`, {});
  }

  /**
   * Duplicate an item
   * @param itemId - The item ID to duplicate
   * @param overrides - Optional data overrides for the new item
   * @returns Duplicated item
   */
  async duplicate(
    itemId: string, 
    overrides?: Partial<ItemCreate>
  ): Promise<Item> {
    return this.post<Item>(`${itemId}/duplicate`, { overrides });
  }

  /**
   * Get items owned by current user
   * @param params - Pagination options
   * @returns List of user's items
   */
  async myItems(params?: PaginationParams): Promise<ItemListResponse> {
    const query = this.buildPaginationParams(params);
    return this.get<ItemListResponse>('me', { params: query });
  }

  /**
   * Search items by name or description
   * @param query - Search query string
   * @param params - Pagination options
   * @returns Filtered list of items
   */
  async search(query: string, params?: PaginationParams): Promise<ItemListResponse> {
    const queryParams = this.buildPaginationParams(params);
    return this.get<ItemListResponse>('search', {
      params: { ...queryParams, q: query },
    });
  }

  /**
   * Get items by status
   * @param status - Status to filter by
   * @param params - Pagination options
   * @returns List of items with the specified status
   */
  async byStatus(status: ItemStatus, params?: PaginationParams): Promise<ItemListResponse> {
    return this.list({ ...params, status });
  }

  /**
   * Bulk update multiple items
   * @param itemIds - Array of item IDs to update
   * @param updates - Update data to apply to all items
   * @returns Updated items
   */
  async bulkUpdate(itemIds: string[], updates: Partial<ItemUpdate>): Promise<Item[]> {
    return this.patch<Item[]>('bulk', {
      ids: itemIds,
      updates,
    } as Record<string, unknown>);
  }

  /**
   * Bulk delete multiple items
   * @param itemIds - Array of item IDs to delete
   * @returns Count of deleted items
   */
  async bulkDelete(itemIds: string[]): Promise<{ deleted: number }> {
    return this.delete<{ deleted: number }>('bulk', {
      data: { ids: itemIds } as Record<string, unknown>,
    } as any);
  }

  /**
   * Update item metadata
   * @param itemId - The item ID
   * @param metadata - Metadata object to merge/update
   * @returns Updated item
   */
  async updateMetadata(
    itemId: string, 
    metadata: Record<string, unknown>
  ): Promise<Item> {
    return this.patch<Item>(`${itemId}/metadata`, { metadata });
  }

  /**
   * Transfer item ownership
   * @param itemId - The item ID
   * @param newOwnerId - ID of the new owner
   * @returns Updated item
   */
  async transferOwner(itemId: string, newOwnerId: string): Promise<Item> {
    return this.post<Item>(`${itemId}/transfer`, {
      new_owner_id: newOwnerId,
    });
  }
}

