        if (this.token && !this.isTokenExpired()) {
          config.headers.Authorization = `Bearer ${this.token.access_token}`;
        }

        // Add API key if provided
        if (this.config.apiKey) {
          config.headers['X-API-Key'] = this.config.apiKey;
        }

        return config;
      },
      (error) => Promise.reject(error)
    );
  }

  /**
   * Setup response interceptor for token refresh and retries
   */
  private setupResponseInterceptor(): void {
    this.client.interceptors.response.use(
      (response) => response,
      async (error) => {
        const originalRequest = error.config as InternalAxiosRequestConfig & {
          _retry?: boolean;
          _retryCount?: number;
        };

        // Handle 401 - Token expired
        if (error.response?.status === 401 && !originalRequest._retry) {
          if (this.isRefreshing) {
            // Wait for current refresh to complete
            try {
              await this.refreshPromise;
              return this.client(originalRequest);
            } catch (refreshError) {
              return Promise.reject(refreshError);
            }
          }

          originalRequest._retry = true;
          this.isRefreshing = true;

          try {
            await this.refreshAccessToken();
            return this.client(originalRequest);
          } catch (refreshError) {
            // Refresh failed, clear auth
            this.token = null;
            throw new RefreshTokenError('Session expired. Please login again.');
          } finally {
            this.isRefreshing = false;
            this.refreshPromise = null;
          }
        }

        // Handle retries for 5xx errors
        if (
          error.response?.status >= 500 &&
          (!originalRequest._retryCount || originalRequest._retryCount < this.config.retries)
        ) {
          originalRequest._retryCount = (originalRequest._retryCount || 0) + 1;

          // Exponential backoff
          const delay = this.config.retryDelay * Math.pow(2, originalRequest._retryCount - 1);
          await new Promise((resolve) => setTimeout(resolve, delay));

          return this.client(originalRequest);
        }

        return Promise.reject(error);
      }
    );
