/**
 * Basic Usage Example
 * Demonstrates SDK initialization and basic operations
 */

const { createClient } = require('../dist/index.js');

// Configuration
const API_BASE_URL = process.env.API_BASE_URL || 'https://api.openclaw.ai/v1';
const API_KEY = process.env.API_KEY || 'your-api-key';

/**
 * Example: Basic SDK Usage
 */
async function basicUsage() {
  // Initialize client
  const client = createClient({
    baseURL: API_BASE_URL,
    apiKey: API_KEY,
    timeout: 30000,
  });

  try {
    // Login
    console.log('Logging in...');
    const token = await client.login({
      username: 'test@example.com',
      password: 'secure-password',
    });
    console.log('Login successful:', token.access_token.slice(0, 20) + '...');

    // Get current user
    console.log('\nFetching current user...');
    const me = await client.users.me();
    console.log('Current user:', me);

    // List users
    console.log('\nListing users...');
    const users = await client.users.list({ page: 1, per_page: 10 });
    console.log(`Found ${users.meta.total} users:`);
    users.users.forEach((user) => {
      console.log(`  - ${user.username} (${user.email})`);
    });

    // Get specific user
    if (users.users.length > 0) {
      const userId = users.users[0].id;
      console.log(`\nFetching user ${userId}...`);
      const user = await client.users.get(userId);
      console.log('User details:', user);
    }

    // Logout
    console.log('\nLogging out...');
    await client.logout();
    console.log('Logout successful!');

  } catch (error) {
    console.error('Error:', error.message);
    if (error.details) {
      console.error('Details:', error.details);
    }
  }
}

/**
 * Example: Error Handling
 */
async function errorHandlingExample() {
  const client = createClient({
    baseURL: API_BASE_URL,
    apiKey: API_KEY,
  });

  try {
    // Try to get non-existent user
    await client.users.get('non-existent-id');
  } catch (error) {
    if (error.code === 'HTTP_404') {
      console.log('User not found (expected error)');
    } else {
      console.error('Unexpected error:', error);
    }
  }
}

// Run examples
async function main() {
  console.log('=== Basic Usage Example ===\n');
  await basicUsage();

  console.log('\n=== Error Handling Example ===\n');
  await errorHandlingExample();
}

main().catch(console.error);

